import "dotenv/config";
import { accessSync, constants, existsSync, mkdirSync } from "node:fs";
import path from "node:path";
import ffmpegStatic from "ffmpeg-static";
import type { ProviderType } from "./provider/types.js";

function required(name: string): string {
  const v = process.env[name];
  if (!v || v.trim() === "") {
    throw new Error(`Missing required env var: ${name}`);
  }
  return v;
}

function parseCommand(raw: string): { command: string; args: string[] } {
  const parts = raw.trim().split(/\s+/);
  if (parts.length === 0) {
    throw new Error("ACP_AGENT_COMMAND is empty");
  }
  return { command: parts[0], args: parts.slice(1) };
}

function buildAgent(): { command: string; args: string[] } {
  const base = parseCommand(process.env.ACP_AGENT_COMMAND ?? "kiro-cli acp");
  const name = (process.env.ACP_AGENT_NAME ?? "").trim();
  if (name && !base.args.includes("--agent")) {
    base.args.push("--agent", name);
  }
  return base;
}

function configuredMemoryDir(): string {
  return path.resolve(
    process.env.MEMORY_DIR && process.env.MEMORY_DIR.trim() !== ""
      ? process.env.MEMORY_DIR
      : "F:\\AI\\AIMemory"
  );
}

function configuredDailyIntelOutputDir(): string {
  return path.resolve(
    process.env.INTEL_OUTPUT_DIR && process.env.INTEL_OUTPUT_DIR.trim() !== ""
      ? process.env.INTEL_OUTPUT_DIR
      : path.join(process.cwd(), "output", "daily-intel")
  );
}

function commandExists(command: string): boolean {
  const pathValue = process.env.PATH ?? process.env.Path ?? "";
  const dirs = pathValue.split(path.delimiter).filter(Boolean);
  const extensions = process.platform === "win32"
    ? (process.env.PATHEXT ?? ".EXE;.CMD;.BAT;.COM").split(";").filter(Boolean)
    : [""];
  for (const dir of dirs) {
    for (const ext of extensions) {
      const candidate = path.join(dir, process.platform === "win32" ? command + ext.toLowerCase() : command);
      try {
        accessSync(candidate, constants.X_OK);
        return true;
      } catch {
        // try next candidate
      }
    }
  }
  return false;
}

export const config = {
  telegramToken: required("TELEGRAM_BOT_TOKEN"),
  agent: buildAgent(),

