{
 "type": "stdio",
 "command": "node",
 "args": [
  "G:\\AI\\telegram-kiro-bridge-main\\dist\\mcp-memory.js"
 ],
 "env": {
  "MEMORY_USER_ID": "509424983",
  "MEMORY_DIR": "G:\\AI\\AIMemory"
 }
}

1	/**
2	 * ingest-ripple.ts — 漣漪式 Wiki 更新
3	 *
4	 * 當新 fact 寫入（remember）時，檢查是否有相關 wiki page 需要更新。
5	 * 設計原則：
6	 * - fire-and-forget，不阻塞 remember 主路徑
7	 * - 不直接改 wiki 頁面（那是 agent 的工作），只產出「待更新」標記
8	 * - 標記累積到門檻後，由 /dream 或 /wikisync 一次性處理
9	 *
10	 * 機制：
11	 * 1. 新 fact 寫入 → 取出 topic → 找到對應 wiki page
12	 * 2. 比對 wiki page 的 sources frontmatter → 算出「新增 facts 數」
13	 * 3. 新增 facts ≥ RIPPLE_THRESHOLD → 追加到 wiki-ripple.jsonl
14	 * 4. /dream 的 wikisync 步驟可讀取 ripple log 決定優先更新哪些頁面
15	 */
16	
17	import { readFileSync, existsSync, appendFileSync, writeFileSync, mkdirSync } from "node:fs";
18	import path from "node:path";
19	import { config } from "./config.js";
20	import { topicToFilename } from "./facts-store.js";
21	
22	// ─── 常數 ─────────────────────────────────────────────────────────────────
23	
24	/** 累積多少新 fact 才標記為需更新 */
25	const RIPPLE_THRESHOLD = 3;
26	
27	/** ripple log 最大筆數（防無界增長） */
28	const MAX_RIPPLE_ENTRIES = 200;
29	
30	/** wiki index 路徑 */
31	const WIKI_INDEX_PATH = path.join(config.memoryDir, "wiki", "index.md");
32	
33	/** ripple log 路徑 */
34	const RIPPLE_LOG_PATH = path.join(config.memoryDir, "wiki", "wiki-ripple.jsonl");
35	
36	// ─── 型別 ─────────────────────────────────────────────────────────────────
37	
38	export interface RippleEntry {
39	  /** ISO timestamp */
40	  ts: string;
41	  /** 觸發此 ripple 的 topic */
42	  topic: string;
43	  /** 對應的 wiki slug（如果有） */
44	  wikiSlug: string | null;
45	  /** wiki page 的 type（concepts / lessons / references） */
46	  wikiType: string | null;
47	  /** 觸發的 fact 文字（截斷） */
48	  factPreview: string;
49	  /** 觸發的 fact ID（f_xxxxxx 格式；追溯用，可能缺） */
50	  factId: string | null;
51	  /** 該 page 目前累積的未同步 fact 數 */
52	  pendingCount: number;
53	  /** 是否達到更新門檻 */
54	  thresholdReached: boolean;
55	}
56	
57	export interface RippleStatus {
58	  /** 需要更新的 wiki page（已達門檻） */
59	  pagesNeedingUpdate: Array<{
60	    slug: string;
61	    type: string;
62	    topic: string;
63	    pendingCount: number;
64	    lastRipple: string;
65	  }>;
66	  /** 尚未達門檻的 page */
67	  pagesWatching: Array<{
68	    slug: string;
69	    type: string;
70	    topic: string;
71	    pendingCount: number;
72	  }>;
73	}
74	
75	// ─── 內部工具 ─────────────────────────────────────────────────────────────
76	
77	/** 解析 wiki/index.md，取得 slug → topic 映射 */
78	function parseWikiIndex(): Map<string, { slug: string; type: string }> {
79	  const map = new Map<string, { slug: string; type: string }>();
80	  if (!existsSync(WIKI_INDEX_PATH)) return map;
81	
82	  try {
83	    const content = readFileSync(WIKI_INDEX_PATH, "utf8");
84	    // 格式：- [[slug]] — 描述
85	    const re = /^-\s*\[\[([^\]]+)\]\]\s*—\s*(.+)$/gm;
86	    let m: RegExpExecArray | null;
87	    let currentType = "concepts";
88	
89	    for (const line of content.split(/\r?\n/)) {
90	      // 偵測 section 標題
91	      if (/^##\s*Pages/i.test(line)) currentType = "concepts";
92	      else if (/^##\s*Lessons/i.test(line)) currentType = "lessons";
93	      else if (/^##\s*References/i.test(line)) currentType = "references";
94	      else if (/^##\s*Tasks/i.test(line)) currentType = "tasks";
95	      else if (/^##\s*Queries/i.test(line)) currentType = "queries";
96	
97	      re.lastIndex = 0;
98	      m = re.exec(line);
99	      if (m) {
100	        const slug = m[1];
101	        // slug 通常就是 topic 名（kebab-case）
102	        map.set(slug, { slug, type: currentType });
103	      }
104	    }
105	  } catch { /* 讀取失敗，回傳空 map */ }
106	  return map;
107	}
108	
109	/** 讀取 wiki page 的 sources frontmatter（fact IDs 列表） */
110	function getPageSources(slug: string, type: string): Set<string> {
111	  const sources = new Set<string>();
112	  const pagePath = path.join(config.memoryDir, "wiki", type, `${slug}.md`);
113	  if (!existsSync(pagePath)) return sources;
114	
115	  try {
116	    const content = readFileSync(pagePath, "utf8");
117	    // frontmatter: sources: [f_xxxxxx, f_yyyyyy, ...]
118	    const match = content.match(/^sources:\s*\[([^\]]*)\]/m);
119	    if (match) {
120	      const ids = match[1].split(",").map((s) => s.trim()).filter(Boolean);
121	      for (const id of ids) sources.add(id);
122	    }
123	  } catch { /* 讀取失敗 */ }
124	  return sources;
125	}
126	
127	/** 讀取 topic shard 的 fact IDs */
128	function getShardFactIds(topic: string): string[] {
129	  const userId = getActiveUserId();
130	  if (!userId) return [];
131	
132	  // topic → filename：kebab-case 對應
133	  const shardDir = path.join(config.memoryDir, `facts_Topic`, String(userId));
134	  if (!existsSync(shardDir)) return [];
135	
136	  // 找到對應 shard 檔案 — 用 facts-store 的 topicToFilename()（與寫入端
137	  // 同一個正規化：lowercase、空白轉 dash、濾特殊字元），避免猜檔名 miss。
138	  const candidates = [path.join(shardDir, topicToFilename(topic))];
139	
140	  for (const filePath of candidates) {
141	    if (!existsSync(filePath)) continue;
142	    try {
143	      const content = readFileSync(filePath, "utf8");
144	      const ids: string[] = [];
145	      for (const line of content.split(/\r?\n/)) {
146	        const m = line.match(/\[f_([0-9a-f]{6})\]/);
147	        if (m) ids.push(`f_${m[1]}`);
148	      }
149	      return ids;
150	    } catch { /* 忽略 */ }
151	  }
152	  return [];
153	}
154	
155	function getActiveUserId(): number | null {
156	  const raw = (process.env.TG_ACTIVE_USER_ID ?? "").trim() ||
157	    (process.env.MEMORY_USER_ID ?? "").trim();
158	  if (raw) {
159	    const n = Number(raw);
160	    if (Number.isFinite(n) && n > 0) return n;
161	  }
162	  try {
163	    const filePath = path.join(config.memoryDir, ".user-id");
164	    const content = readFileSync(filePath, "utf8").trim();
165	    const n = Number(content);
166	    if (Number.isFinite(n) && n > 0) return n;
167	  } catch { /* 忽略 */ }
168	  return null;
169	}
170	
171	// ─── 公開 API ─────────────────────────────────────────────────────────────
172	
173	/**
174	 * 新 fact 寫入時呼叫。fire-and-forget，不拋錯。
175	 * @param topic - 該 fact 被分類到的 topic
176	 * @param factText - fact 原文（用於 preview）
177	 * @param factId - fact ID（如 f_abc123）
178	 */
179	export function onFactIngested(topic: string, factText: string, factId?: string): void {
180	  try {
181	    const wikiIndex = parseWikiIndex();
182	
183	    // 找到對應的 wiki page（topic slug = wiki slug）
184	    const wikiEntry = wikiIndex.get(topic);
185	    const wikiSlug = wikiEntry?.slug ?? null;
186	    const wikiType = wikiEntry?.type ?? null;
187	
188	    // 計算 pending count
189	    let pendingCount = 1;
190	    if (wikiSlug && wikiType) {
191	      const pageSources = getPageSources(wikiSlug, wikiType);
192	      const shardIds = getShardFactIds(topic);
193	      // 未被 wiki page 追蹤的 fact 數
194	      pendingCount = shardIds.filter((id) => !pageSources.has(id)).length;
195	    }
196	
197	    const entry: RippleEntry = {
198	      ts: new Date().toISOString(),
199	      topic,
200	      wikiSlug,
201	      wikiType,
202	      factPreview: factText.slice(0, 100),
203	      factId: factId ?? null,
204	      pendingCount,
205	      thresholdReached: pendingCount >= RIPPLE_THRESHOLD,
206	    };
207	
208	    // 寫入 ripple log
209	    const dir = path.dirname(RIPPLE_LOG_PATH);
210	    if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
211	    appendFileSync(RIPPLE_LOG_PATH, JSON.stringify(entry) + "\n", "utf8");
212	
213	    // 體積控制：超過上限時截斷
214	    trimRippleLog();
215	  } catch (err) {
216	    // ripple 是旁路訊號，絕不影響主路徑
217	    console.error("[ingest-ripple] failed:", err);
218	  }
219	}
220	
221	/**
222	 * 取得目前的 ripple 狀態（供 /dream wikisync 步驟讀取）。
223	 */
224	export function getRippleStatus(): RippleStatus {
225	  const status: RippleStatus = {
226	    pagesNeedingUpdate: [],
227	    pagesWatching: [],
228	  };
229	
230	  if (!existsSync(RIPPLE_LOG_PATH)) return status;
231	
232	  try {
233	    const content = readFileSync(RIPPLE_LOG_PATH, "utf8");
234	    const lines = content.trim().split("\n").filter(Boolean);
235	
236	    // 聚合：per-topic 取最新一筆
237	    const latestByTopic = new Map<string, RippleEntry>();
238	    for (const line of lines) {
239	      try {
240	        const entry: RippleEntry = JSON.parse(line);
241	        const existing = latestByTopic.get(entry.topic);
242	        if (!existing || entry.ts > existing.ts) {
243	          latestByTopic.set(entry.topic, entry);
244	        }
245	      } catch { /* 跳過 */ }
246	    }
247	
248	    for (const entry of latestByTopic.values()) {
249	      if (!entry.wikiSlug) continue; // 沒有對應 wiki page 的跳過
250	
251	      if (entry.thresholdReached) {
252	        status.pagesNeedingUpdate.push({
253	          slug: entry.wikiSlug,
254	          type: entry.wikiType!,
255	          topic: entry.topic,
256	          pendingCount: entry.pendingCount,
257	          lastRipple: entry.ts,
258	        });
259	      } else {
260	        status.pagesWatching.push({
261	          slug: entry.wikiSlug,
262	          type: entry.wikiType!,
263	          topic: entry.topic,
264	          pendingCount: entry.pendingCount,
265	        });
266	      }
267	    }
268	
269	    // 按 pendingCount 降序
270	    status.pagesNeedingUpdate.sort((a, b) => b.pendingCount - a.pendingCount);
271	  } catch { /* 讀取失敗 */ }
272	
273	  return status;
274	}
275	
276	/**
277	 * 清除已處理的 ripple 記錄（wikisync 完成後呼叫）。
278	 * @param processedTopics - 已成功更新的 topic 列表
279	 */
280	export function clearProcessedRipples(processedTopics: string[]): void {
281	  if (!existsSync(RIPPLE_LOG_PATH)) return;
282	
283	  try {
284	    const content = readFileSync(RIPPLE_LOG_PATH, "utf8");
285	    const lines = content.trim().split("\n").filter(Boolean);
286	    const topicSet = new Set(processedTopics);
287	
288	    const remaining = lines.filter((line) => {
289	      try {
290	        const entry: RippleEntry = JSON.parse(line);
291	        return !topicSet.has(entry.topic);
292	      } catch { return true; }
293	    });
294	
295	    writeFileSync(RIPPLE_LOG_PATH, remaining.join("\n") + (remaining.length ? "\n" : ""), "utf8");
296	  } catch (err) {
297	    console.error("[ingest-ripple] clearProcessedRipples failed:", err);
298	  }
299	}
300	
301	/** 體積控制：保留最後 MAX_RIPPLE_ENTRIES 筆 */
302	function trimRippleLog(): void {
303	  try {
304	    const content = readFileSync(RIPPLE_LOG_PATH, "utf8");
305	    const lines = content.trim().split("\n").filter(Boolean);
306	    if (lines.length <= MAX_RIPPLE_ENTRIES) return;
307	
308	    const trimmed = lines.slice(-MAX_RIPPLE_ENTRIES);
309	    writeFileSync(RIPPLE_LOG_PATH, trimmed.join("\n") + "\n", "utf8");
310	  } catch { /* 忽略 */ }
311	}
