import path from "node:path";
import {
  classifyFact,
  invalidateTopicRulesCache,
  resolveTopicsFile,
  type TopicRule,
} from "./topic-rules.js";

/** Resolve the active MEMORY_DIR, mirroring config.ts/mcp-memory.ts. */
export function resolveMemoryDir(): string {
  const raw = (process.env.MEMORY_DIR ?? "").trim();
  return path.resolve(raw !== "" ? raw : "F:\\AI\\AIMemory");
}

/** Master append-only log — single source of truth. */
export function masterFactsFile(userId: number | string): string {
  return path.join(resolveMemoryDir(), `facts-${userId}.md`);
}

/** Directory holding this user's topic shards. */
export function userShardDir(userId: number | string): string {
  return path.join(resolveMemoryDir(), "facts_Topic", String(userId));
}

