 * @param factId - fact ID（如 f_abc123）
 */
export function onFactIngested(topic: string, factText: string, factId?: string): void {
  try {
    const wikiIndex = parseWikiIndex();

    // 找到對應的 wiki page（topic slug = wiki slug）
    const wikiEntry = wikiIndex.get(topic);
    const wikiSlug = wikiEntry?.slug ?? null;
    const wikiType = wikiEntry?.type ?? null;

    // 計算 pending count
    let pendingCount = 1;
    if (wikiSlug && wikiType) {
      const pageSources = getPageSources(wikiSlug, wikiType);
      const shardIds = getShardFactIds(topic);
      // 未被 wiki page 追蹤的 fact 數
      pendingCount = shardIds.filter((id) => !pageSources.has(id)).length;
    }

    const entry: RippleEntry = {
      ts: new Date().toISOString(),
      topic,
      wikiSlug,
      wikiType,
      factPreview: factText.slice(0, 100),
      factId: factId ?? null,
      pendingCount,
      thresholdReached: pendingCount >= RIPPLE_THRESHOLD,
    };

    // 寫入 ripple log
    const dir = path.dirname(RIPPLE_LOG_PATH);
    if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
    appendFileSync(RIPPLE_LOG_PATH, JSON.stringify(entry) + "\n", "utf8");

    // 體積控制：超過上限時截斷
    trimRippleLog();
  } catch (err) {
    // ripple 是旁路訊號，絕不影響主路徑
    console.error("[ingest-ripple] failed:", err);
  }
}

/**
 * 取得目前的 ripple 狀態（供 /dream wikisync 步驟讀取）。
 */
export function getRippleStatus(): RippleStatus {
  const status: RippleStatus = {
    pagesNeedingUpdate: [],
    pagesWatching: [],
  };

  if (!existsSync(RIPPLE_LOG_PATH)) return status;

  try {
    const content = readFileSync(RIPPLE_LOG_PATH, "utf8");
    const lines = content.trim().split("\n").filter(Boolean);

    // 聚合：per-topic 取最新一筆
    const latestByTopic = new Map<string, RippleEntry>();
    for (const line of lines) {
      try {
        const entry: RippleEntry = JSON.parse(line);
        const existing = latestByTopic.get(entry.topic);
        if (!existing || entry.ts > existing.ts) {
          latestByTopic.set(entry.topic, entry);
        }
      } catch { /* 跳過 */ }
    }

    for (const entry of latestByTopic.values()) {
      if (!entry.wikiSlug) continue; // 沒有對應 wiki page 的跳過

      if (entry.thresholdReached) {
        status.pagesNeedingUpdate.push({
          slug: entry.wikiSlug,
          type: entry.wikiType!,
          topic: entry.topic,
          pendingCount: entry.pendingCount,
          lastRipple: entry.ts,
        });
      } else {
        status.pagesWatching.push({
          slug: entry.wikiSlug,
          type: entry.wikiType!,
          topic: entry.topic,
          pendingCount: entry.pendingCount,
        });
      }
    }

    // 按 pendingCount 降序
    status.pagesNeedingUpdate.sort((a, b) => b.pendingCount - a.pendingCount);
  } catch { /* 讀取失敗 */ }

  return status;
}

/**
 * 清除已處理的 ripple 記錄（wikisync 完成後呼叫）。
 * @param processedTopics - 已成功更新的 topic 列表
 */
export function clearProcessedRipples(processedTopics: string[]): void {
  if (!existsSync(RIPPLE_LOG_PATH)) return;

  try {
    const content = readFileSync(RIPPLE_LOG_PATH, "utf8");
    const lines = content.trim().split("\n").filter(Boolean);
    const topicSet = new Set(processedTopics);

    const remaining = lines.filter((line) => {
      try {
        const entry: RippleEntry = JSON.parse(line);
        return !topicSet.has(entry.topic);
      } catch { return true; }
    });

    writeFileSync(RIPPLE_LOG_PATH, remaining.join("\n") + (remaining.length ? "\n" : ""), "utf8");
  } catch (err) {
    console.error("[ingest-ripple] clearProcessedRipples failed:", err);
  }
}

/** 體積控制：保留最後 MAX_RIPPLE_ENTRIES 筆 */
function trimRippleLog(): void {
  try {
    const content = readFileSync(RIPPLE_LOG_PATH, "utf8");
    const lines = content.trim().split("\n").filter(Boolean);
    if (lines.length <= MAX_RIPPLE_ENTRIES) return;

    const trimmed = lines.slice(-MAX_RIPPLE_ENTRIES);
    writeFileSync(RIPPLE_LOG_PATH, trimmed.join("\n") + "\n", "utf8");
  } catch { /* 忽略 */ }
}

